INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02290297', NULL, 'PEQUEÑO PAÍS del nº 1 al 200', 1981, NULL, 'Revista de historietas de venta conjunta con "El País Semanal", suplemento dominical del diario El País, que se entregaba integrada en la paginación del suplemento.  La idea inicial partió de Rosa Montero, a la sazón redactora jefe de "El País Semanal", que encargó la creación del tebeo al ilustrador Gerardo R. Amechazurra. El dibujante, con la colaboracion de Lolo Rico, escritora con la que trabajaba entonces en equipo en otras tareas, hizo realidad aquel proyecto, para el que ambos aportaron la historieta `Cosas de casa?. Entre los componentes del equipo inicial se contaban Juan Carlos Eguillor (autor de las portadas de la primera época, que comenzaron siendo caricaturas de famosos artistas para acabar convirtiéndose en `Los cuentos de la abuelita?), Tino Gatagán (otro de los dibujantes de la plantilla del periódico), la fotógrafa Anel Fernández y varios redactores que por lo común no firmaban sus aportaciones. BUEN ESTADO, ENCUADERNACION GUAFLEX ROJO', NULL, 28737, 94490, 495.0, 'Almacén', '2025-09-01', TRUE, NULL, 1, 'wwaa', FALSE, FALSE, FALSE, NULL)
