VALUES ('02290322', '8466315071', 'La cultura. Todo lo que hay que saber', NULL, 187, 'La cultura. Todo lo que hay que saber es un ensayo del autor alemán Dietrich Schwanitz que explora el concepto de cultura y su importancia en la sociedad moderna. El libro abarca una amplia gama de temas, desde la historia del arte y la literatura hasta la música, la filosofía y la ciencia, ofreciendo una visión completa de la cultura occidental. Schwanitz analiza cómo la cultura influye', NULL, 28740, 1268, 8.0, 'Almacén', '2025-09-01', TRUE, NULL, 1, 'Dietrich Schwanitz', FALSE, FALSE, FALSE, NULL)
