VALUES ('02290704', NULL, 'CUERPO HUMANO LIBRO PUZZLE', NULL, NULL, 'GRAN FORMATO. El cuerpo humano es una maravilla de la naturaleza pero... ¿Qué ocurre bajo la piel? ¿Cómo se mueve el cuerpo? ¿Cómo trabajan los músculos? ¿Qué son los cinco sentidos? Los 5 puzles de 48 piezas que incluye este libro guiarán a los niños en un viaje lleno de descubrimientos inolvidables a través del esqueleto, el sistema nervioso central, el sistema circulatorio, los músculos y el aparato digestivo. Además debajo de cada puzle encontrarán otros sorprendentes datos, que les enseñarán el funcionamiento de nuestro cuerpo mientras forman correctamente los puzzles.Con 5 puzles de 48 piezas:- El esqueleto.- El sistema nervioso central.- El sistema circulatori.- Los músculos.- El aparato digestivo.', NULL, 28746, 1304, 29.0, 'Almacén', '2025-09-12', TRUE, NULL, 1, 'AA.VV', FALSE, FALSE, FALSE, NULL)
