VALUES ('02290757', NULL, 'División 250', 1971, 417, 'Cartoné. BUEN ESTADO.   "División 250" se refiere a la novela de Tomás Salvador y la obra de teatro, que narran la experiencia de la División Azul, unidad española de voluntarios que luchó junto a la Wehrmacht alemana en el frente oriental contra la Unión Soviética durante la Segunda Guerra Mundial. El libro de Salvador ofrece una perspectiva humana y "coral" de los combatientes, centrándose en el día a día y la valentía de los soldados en un contexto bélico muy duro', NULL, 28746, 94216, 20.0, 'Almacén', '2025-09-14', TRUE, NULL, 1, 'SALVADOR, Tomás', FALSE, FALSE, FALSE, NULL)
