INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02290839', '978-84-670-4809-4', 'Cantar de mio Cid', 2016, 1178, 'Biblioteca clásica de la Real Academia Española. 2ª ed. edición. 21 cm. Poema del Cid. Edición, estudio y notas de Alberto Montaner ; con un ensayo de Francisco Rico. Índice. En la portada: Real Academia Española. Montaner Frutos, Alberto. 1963-. editor literario. Rico, Francisco. 1942-2024..El volumen incluye, junto a la edición anotada del texto, un ensayo de Francisco Rico titulado Un canto de frontera: «La gesta de Mio Cid el de Bivar» y estudios de Alberto Montaner que abordan cuestiones como la composición de la obra, el poema épico y su contexto, la constitución interna del Cantar y la historia del texto.  La épica consiste, como ya definía Aristóteles, en la representación de un héroe esforzado mediante una narración poética. En el caso del Cantar de Mio Cid tal presentación resulta perfectamente ajustada a su contenido y refleja lo que podría considerarse la línea maestra de su construcción interna.', NULL, NULL, 56, 33.9, 'Almacén', '2025-09-15', TRUE, NULL, 1, NULL, FALSE, FALSE, FALSE, NULL)
