VALUES ('02291198', NULL, 'EL BAÑO DE SANGRE - TRES BAÚLES Y UN ATAÚD', NULL, NULL, 'RUSTICA, BUEN ESTADO. 1ª edición. Rústica con solapas. 125 pp. 16 x 24 cm. Fotografías b/n y dibujos del autor. Juan de la Cruz fue un dramaturgo singular, cofundador de la compañía Profetas de Mueble Bar, que marcó la escena teatral del archipiélago canario. Su estilo se caracteriza por:  Una gestualidad rica y una impronta plástica que dilata el espacio entre frases', NULL, NULL, 25021, 18.0, 'Almacén', '2025-10-04', TRUE, NULL, 1, 'Juan de la Cruz', FALSE, FALSE, FALSE, NULL)
