VALUES ('02291308', NULL, 'Ronda, ciudad de los encantos', NULL, NULL, 'Ronda, ciudad de los encantos de Federico Lozano Gutiérrez, publicado por Autor-Editor, es una obra que celebra la riqueza histórica, cultural y paisajística de la ciudad de Ronda, en la provincia de Málaga, España. Este libro funciona como una guía cultural y visual, pero con un tono poético y evocador. No es solo una descripción turística, sino una invitación a sentir Ronda: sus calles, sus leyendas, sus personajes y su arquitectura suspendida entre el cielo y el abismo. APAISADO', NULL, 28746, 7415, 49.0, 'Almacén', '2025-10-05', TRUE, NULL, 1, 'Federico Lozano Gutiérrez,', FALSE, FALSE, FALSE, NULL)
