VALUES ('02291309', NULL, 'Comentarios de la pintura encáustica del pincel', 1795, NULL, 'Comentarios de la pintura encáustica del pincel de Pedro García de la Huerta es una obra singular dentro de la literatura técnica y artística del siglo XVIII. Aquí te comparto los detalles esenciales. Este libro no es solo un manual: es una meditación sobre el arte como ritual de permanencia. La encáustica, al fundir fuego, color y materia, se convierte en una metáfora de lo eterno. El pincel no pinta solo formas, sino memorias que resisten el tiempo. Encuadernación piel época con alguna falta, falta portadilla interior. restos de humedad ultimas paginas', NULL, 28746, 25021, 350.0, 'Almacén', '2025-10-05', TRUE, NULL, 1, 'Pedro García de la Huerta', FALSE, FALSE, FALSE, NULL)
