INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02291322', '9788449325892', 'La humanidad amenazada :: gobernar los riesgos globales', 2011, 334, 'Estado y Sociedad. Los riesgos globales son uno de los problemas centrales de la humanidad: desde el 11-S habíamos adquirido una clara conciencia de la vulnerabilidad de nuestras sociedades; muchos desastres ecológicos eran un hecho cumplido y otros se asomaban a nuestra vida, como el cambio climático o los desastres sociales provocados por la crisis económica. Sin embargo, diversos acontecimientos recientes, como las catástrofes recientemente sucedidas en Japón o la inestabilidad en el sur del Mediterráneo nos hacen sentir que estamos inmersos en una cadena de riesgos difíciles de controlar. Mediante los textos de expertos de reconocida solvencia internacional, esta obra nos proporciona una nueva reflexión acerca de los principios de prevención,', NULL, NULL, 1395, 12.0, 'Almacén', '2025-10-06', TRUE, NULL, 1, 'Solana, Javier and Innerarity, Daniel', FALSE, FALSE, FALSE, NULL)
