INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02291334', '9783836584685', 'Her Majesty. A Photographic History 1926-2022', NULL, NULL, 'gran formato tela con sobrecubierta. Tapa dura. Estado: Nuevo. Nuevo - ¡Celebre a Su Majestad la Reina Isabel II con este magnífico reportaje fotográfico sobre su vida pública y privada! Esta colección de imágenes reales, llena de ostentación y glamour, kitsch y cultura, muestra viajes al extranjero, recepciones de estado, bodas reales, carreras de caballos, desfiles de sombreros, corgis y aniversarios. Entre las fotografías se encuentran los legendarios retratos oficiales de Cecil Beaton, Yousuf Karsh, Dorothy Wilding y Lord Snowdon, así como tomas originales de Patrick Lichfield, Annie Leibovitz, Rankin y muchos otros. (Texto en alemán, inglés y francés) 368 págs. Alemán, inglés y francés.', NULL, NULL, 228, 30.0, 'Almacén', '2025-10-06', TRUE, NULL, 1, 'Warwick, Christopher', FALSE, FALSE, FALSE, NULL)
