VALUES ('02291353', NULL, 'Trajes Populares y Costumbres Tradicionales. Tesoro del Folklore Español. Prólogo de Julio Caro Baroja.', NULL, NULL, 'TELA. Folio. 225 pp + 1 h. Con fotografías e ilustraciones de Alfredo Ibarra. Encuadernación tela editorial BUEN ESTADO. , escrito por José Manuel Gómez-Tabanera y publicado en Madrid en 1950, es una obra etnográfica que recoge con detalle la indumentaria y las costumbres tradicionales de las distintas regiones de España, con especial atención a Madrid y su entorno. Es parte de la colección Ediciones Siglo XX, y cuenta con prólogo de Julio Caro Baroja, lo que ya indica su seriedad antropológica y su sensibilidad hacia lo simbólico.', NULL, 28753, 25021, 59.0, 'Almacén', '2025-10-07', TRUE, NULL, 1, 'GÓMEZ-TABANERA, José Manuel.', FALSE, FALSE, FALSE, NULL)
