INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02291754', NULL, 'Real Picadero: Notas y apostillas para una edición de las láminas del Real Picadero de Carlos IV', NULL, NULL, 'Real Picadero: Notas y apostillas para una edición de las láminas del Real Picadero de Carlos IV, publicado por Frame en 1996, es una joya editorial que rescata y comenta una serie de láminas de equitación del siglo XVIII, vinculadas al entorno cortesano del reinado de Carlos IV. Es una obra colectiva (VVAA) que actúa como edición crítica y facsímil, con anotaciones que iluminan el contexto histórico, artístico y técnico de las imágenes. 12 láminas grabadas originalmente por artistas como Antonio Carnicero, que ilustran técnicas ecuestres y escenas del Real Picadero. Notas y apostillas que explican el simbolismo, la técnica de grabado, y el uso ceremonial o pedagógico de cada imagen.  Una edición cuidada, con encuadernación en tela y detalles como el Escudo Real en la cubierta. ENCUADERNACION EN SEDA', NULL, NULL, 25021, 49.0, 'Almacén', '2025-10-20', TRUE, NULL, 1, 'wwaa INTRODUCCION ALVAREZ BARRIOS', FALSE, FALSE, FALSE, NULL)
