INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02291951', '84-89787-00-X', 'Tratado de odontología 4 VOL', 2000, 4, '1ª ed. edición. 31 cm. Coordinador general,  Antonio Bascones Martínez. Guardado en caja. Odontología..El Tratado de Odontología de Antonio Bascones Martínez, una obra de referencia en el ámbito de la estomatología.Contenido y relevancia  Esta obra monumental está compuesta por cuatro volúmenes que abarcan de forma exhaustiva las distintas ramas de la odontología, incluyendo:  Anatomía y fisiología bucodentalDiagnóstico clínico y radiológico Periodoncia, cirugía oral y maxilofacial Prótesis, ortodoncia y odontopediatría  Patología oral y medicina bucal. Es un compendio dirigido tanto a estudiantes de odontología como a profesionales clínicos, con un enfoque académico riguroso y actualizado para su época. Su autor, Antonio Bascones Martínez, es una figura destacada en la estomatología española, con una amplia trayectoria docente e investigadora.El Tratado de Odontología se considera una obra de consulta esencial en facultades de odontología y bibliotecas médicas. Su estructura por tomos permite una especialización progresiva, y su lenguaje técnico está acompañado de ilustraciones y esquemas que facilitan la comprensión de los procedimientos clínicos.', NULL, NULL, 5350, 275.0, 'Almacén', '2025-10-31', TRUE, NULL, 1, 'Antonio Bascones Martinez Y OTROS MUCHOS COLABORADORES.', FALSE, FALSE, FALSE, NULL)
