VALUES ('02291980', NULL, 'Pequeños movimientos dentarios en Odontología general', 1969, 636, 'Tela ed. ilustrado. PEQUEÑOS MOVIMIENTOS DENTARIOS EN ODONTOLOGÍA GENERAL. HIRSCHFELD, Leonard y GEIGER, Arnold. Editorial Mundi, S.A.C.I.F. Libro de Edición Argentina. Año 1969. XII + 636 pag mas colofón y hoja de cortesía con 604 ilustraciones, figuras y fotografías en b/n. Tamaño 185x270mm. Tapa dura en plena tela color granate con dorados sobre tejuelo en lomo. Señales normales de libro usado bien cuidado. Bisagras impecables y cortes simétricos, sin óxidos, taras ni mermas, sin datos ni rastros de anteriores poseedores. Excelente ejemplar, raro y escaso, más en este magnífico estado de conservación, un clásico de la odontología. sello expurgo', NULL, 28753, 6944, 59.0, 'Almacén', '2025-11-01', TRUE, NULL, 1, 'Hirschfeld, Leonard; Geiger, Arnold', FALSE, FALSE, FALSE, NULL)
