VALUES ('02292036', NULL, 'Title: Les assurances aériennes.', NULL, NULL, 'RUSTICA. INTONSO. "Les assurances aériennes" (1930), de René Blum, es un estudio jurídico pionero sobre los seguros aplicados a la aviación, en un momento en que el transporte aéreo comenzaba a desarrollarse como industria moderna. La obra analiza el marco legal y técnico de los seguros aeronáuticos en Francia y Europa a comienzos del siglo XX, cuando la aviación civil y comercial estaba en pleno auge. René Blum, doctor en derecho, examina los riesgos específicos del transporte aéreo y cómo deben ser cubiertos por contratos de seguros', NULL, 28746, 25021, 120.0, 'Almacén', '2025-11-01', TRUE, NULL, 1, 'Author: Blum, René', FALSE, FALSE, FALSE, NULL)
