INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02292049', '9788440424938', 'La Eterna Andalucía  ESTUCHE 2 TOMOS', 1988, NULL, 'RUSTICA. Esta guía monumental ofrece una exploración detallada de Andalucía a pie, recorriendo sus paisajes, pueblos, rutas históricas y enclaves naturales. Incluye textos caligrafiados en castellano, con resúmenes en alemán, francés e inglés, lo que la convierte en una obra accesible para lectores internacionales.  Está ilustrada en blanco y negro, con mapas, dibujos y anotaciones que enriquecen la experiencia del lector caminante. Valor cultural  Más que una guía turística, es una obra de autor que celebra la identidad andaluza desde una perspectiva íntima y poética. Ideal para amantes del senderismo, la historia local, la geografía cultural y la literatura de viaje.', NULL, NULL, 7522, 24.0, 'Almacén', '2025-11-02', TRUE, NULL, 1, 'Martínez, Alberto', FALSE, FALSE, FALSE, NULL)
