INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02292290', NULL, 'LA ADVOCACIÓN LAURETANA EN EL EJÉRCITO DEL AIRE. ORIGEN, EXPANSIÓN Y ÁMBITOS DE INFLUENCIA.', NULL, NULL, 'CARTONE CON SOBRECUBIERTALa advocación lauretana en el Ejército del Aire español tiene su origen en la devoción a la Virgen de Loreto, y se ha consolidado como un símbolo espiritual y protector de los aviadores desde principios del siglo XX. Origen de la advocación lauretana La Virgen de Loreto es una advocación mariana vinculada a la Santa Casa de Nazaret, que según la tradición fue trasladada milagrosamente a Loreto (Italia) en el siglo XIII. Su relación con la aviación comenzó en 1920, cuando el papa Benedicto XV la proclamó patrona de todos los aviadores, debido al carácter milagroso de su "vuelo" desde Tierra Santa hasta Italia. En España, esta devoción fue adoptada por el Ejército del Aire tras su creación en 1939, consolidándose como patrona oficial en 1948.La advocación lauretana en el Ejército del Aire español tiene su origen en la devoción a la Virgen de Loreto, y se ha consolidado como un símbolo espiritual y protector de los aviadores desde principios del siglo XX.    &#9992;&#65039; Origen de la advocación lauretana  La Virgen de Loreto es una advocación mariana vinculada a la Santa Casa de Nazaret, que según la tradición fue trasladada milagrosamente a Loreto (Italia) en el siglo XIII.    Su relación con la aviación comenzó en 1920, cuando el papa Benedicto XV la proclamó patrona de todos los aviadores, debido al carácter milagroso de su "vuelo" desde Tierra Santa hasta Italia.    En España, esta devoción fue adoptada por el Ejército del Aire tras su creación en 1939, consolidándose como patrona oficial en 1948.    &#127757; Expansión', NULL, NULL, 25021, 32.0, 'Almacén', '2025-11-10', TRUE, NULL, 1, 'FERNÁNDEZ GARCÍA, José', FALSE, FALSE, FALSE, NULL)
