VALUES ('02292328', '978-84-937830-4-4', 'Quemar la casa: orígenes de un director', 2010, 335, 'Biblioteca Teatro Laboratorio. n. 1. 1ª ed. edición. 21 cm. Traducción, Ana Woolf. "Quemar la casa: Orígenes de un director" es un libro escrito por Eugenio Barba, un reconocido director de teatro, que detalla su proceso creativo y su visión del teatro a lo largo de 14 años. El título hace referencia a un espectáculo que él imaginó y que trata sobre el fuego, aunque aclara que en realidad no quemará su "casa" (el teatro Odin Teatret) de forma literal. La obra invita tanto a artistas como a espectadores a explorar el laberinto personal de la creación teatral.', NULL, NULL, 90634, 39.0, 'Almacén', '2025-11-11', TRUE, NULL, 1, 'Barba, Eugenio', FALSE, FALSE, FALSE, NULL)
