VALUES ('02292351', NULL, 'Posetas. Poemario', NULL, 214, 'POSIBLE DEDICATORIA AUTORM RUSTICA. Personas de mirada penetrante para descubrir, tras la opacidad del mundo que nos rodea, la luz y la verdad de las cosas que importa. Este es el caso de Matías Solana. Ilustrado a color BUEN ESTADO.', NULL, 28746, 25021, 12.0, 'Almacén', '2025-11-12', TRUE, NULL, 1, 'Solana Hernández, Matías', FALSE, FALSE, FALSE, NULL)
