VALUES ('02292361', '978-84-398-9357-8', 'Federico Mompou : vida, textos y documentos', 1987, 512, 'rúst.. buen estado El libro Federico Mompou: vida, textos y documentos es un estudio sobre la vida del compositor español Federico Mompou, con un enfoque en sus obras para piano, sus escritos y documentos relacionados con su trayectoria. Se centra en la figura de Mompou como compositor de música breve e intimista, explorando sus influencias y sus piezas más famosas, como las Escenas de niños y Música Callada.', NULL, 28758, NULL, 49.0, 'Almacén', '2025-11-12', TRUE, NULL, 0, 'Janes, Clara', FALSE, FALSE, FALSE, NULL)
