VALUES ('02292374', NULL, 'LA SALUD POR LOS CAMPOS MAGNÉTICOS', 2007, NULL, 'La energioterapia se fundamenta en orientarse adecuadamente, con objeto de dirigir hacia el cuerpo un determinado nivel de la energía magnética terrestre, a fin de recuperar aquellas áreas orgánicas que carecen de energía suficiente para estar sanas. Para que el flujo energético alcance el organismo es preciso orientarse hacia las líneas del campo magnético, que siempre circulan en ángulo recto de la corriente que les da origen. RUSTICA, 2º EDICION', NULL, NULL, 7522, 24.0, 'Almacén', '2025-11-12', TRUE, NULL, 1, 'MARCEL GYSENS', FALSE, FALSE, FALSE, NULL)
