VALUES ('02292500', '9782842790295', 'Eléments fondamentaux de la phrase chinoise Darrobers, Robert  Publicado por YOU FENG, 2000  ISBN 10: 2842790294 / ISBN 13: 9782842790295', NULL, 281, 'RUSTICA. El libro Éléments fondamentaux de la phrase chinoise de Roger Darrobers (publicado por You Feng en 2000) es una introducción a la gramática básica del chino, centrada en cómo se construyen las frases.Cada explicación se acompaña de ejemplos prácticos en chino, con transcripción en pinyin y traducción al francés (aunque fácilmente comprensible para estudiantes hispanohablantes).', NULL, NULL, 25021, 15.0, 'Almacén', '2025-11-17', TRUE, NULL, 1, 'Darrobers, Robert', FALSE, FALSE, FALSE, NULL)
