VALUES ('02292552', NULL, 'Historia de las Relaciones Exteriores de España durante el siglo XIX: Apuntes para una historia diplomática. Tomo I: 1839-1838 y tomo II 1839-1868', NULL, NULL, 'Tema central: Analiza la evolución de la diplomacia española a lo largo del siglo XIX, un período marcado por crisis internas, pérdida de colonias y redefinición del papel internacional de España. DOS tomos, cada uno dedicado a etapas específicas del siglo XIX, con especial atención a los tratados, embajadas y conflictos internacionales. BUEN ESTADO, tomo dos desencuadernad LA LOMERA. La cuestión colonial: Cuba, Filipinas y Marruecos como escenarios clave de la diplomacia española.', NULL, 28746, 25021, 495.0, 'Almacén', '2025-11-20', TRUE, NULL, 1, 'Jerónimo Bécker / Carlos Caba Carrera (coord.)', FALSE, FALSE, FALSE, NULL)
