VALUES ('02292667', NULL, 'LA RABIDA. HISTORIA DOCUMENTAL CRITICA (4 VOLUMENES)', 1925, NULL, 'La Rábida. Historia documental crítica ( 4 Vols.) Tomo I. Epocas Legendario - Tradicional e histórica antigua. Tomo II. Epoca Colombina I. La Rabida, Colón y el descubrimiento de América 1485-1506. Tomo III. Epoca Colombina II. La Rabida, Colon y los Marinos del Tinto-Odiel en el descubrimiento de América. Tomo IV Continuación. firma, buen estado. El monasterio franciscano se convierte en un umbral entre lo espiritual y lo histórico. Allí se gestó el apoyo a Colón, y Ortega lo presenta como un espacio donde la fe y la aventura se entrelazan. firma', NULL, NULL, 25021, 80.0, 'Almacén', '2025-11-24', TRUE, NULL, 1, 'P. angel Ortega, OFM', FALSE, FALSE, FALSE, NULL)
