VALUES ('02292750', NULL, 'Los cazadores de microbios', 1946, NULL, 'Completamente nuevo. Directo de la Casa Editora Porrúa. Paul de Kruif, como médico bacteriólogico que posee grandes conocimientos, no se aparta de la verdad científica, y como escritor de pluma ágil y amena describe en Los cazadores de microbios todos los tropiezos y vicisitudes con que lucharon catorce sabios de distinta nacionalidad, de tendencias y caracteres opuestos; pero todos héroes de la voluntad, hasta llegar a la meta propuesta. El autor analiza el carácter, cualidades y defectos de sus personajes; adivina sus pensamientos, y establece los diálogos que hayan podido', NULL, NULL, 891, 16.0, 'Almacén', '2025-12-01', TRUE, NULL, 1, 'Kruif, Paul de', FALSE, FALSE, FALSE, NULL)
