VALUES ('02292793', '9788445325742', 'Reseña del libro "juntas del reino de galicia. TOMO VII actas  VII. 1655-1665.', NULL, NULL, 'TELA. las Juntas eran una institución representativa del Reino de Galicia, formada por procuradores de las ciudades gallegas, que trataban asuntos políticos, económicos y administrativos. Valor histórico: las actas reflejan debates sobre impuestos, defensa del territorio, relaciones con la Corona y la gestión de recursos en un contexto de crisis y guerras en la Monarquía Hispánica del siglo XVII.', NULL, 28746, 25021, 69.0, 'Almacén', '2025-12-08', TRUE, NULL, 1, 'WWAA', FALSE, FALSE, FALSE, NULL)
