INSERT INTO public.libros (legacy_id, isbn, titulo, anio, paginas, descripcion, notas, categoria_id, editorial_id, precio, ubicacion, fecha_ingreso, activo, imagen_url, stock, autor, destacado, novedad, oferta, precio_original)
VALUES ('02292882', '9788439725992', 'El último testamento', 2012, 314, 'Literatura Random House. Frey, James 1969-. The final testament of the Holy Bible. ¿Qué harías si descubrieras que el Mesías viviera hoy? Que viviera en Nueva York. Que se acostara con hombres y dejara embarazadas a las mujeres. Que ayudara a morir a los moribundos, que sanara a los enfermos. Que desafiara al gobierno y que condenara lo sagrado. ¿Qué harías si lo conocieras? ¿Y si cambiara tu vida? ¿Creerías? ¿Sí?James Frey es un escritor que juega con la verdad. Revolucionario y polémico, tuvo que exiliarse de Estados Unidos y esconderse en Francia. Sus libros habitan en esa ambigua línea que existe entre la realidad y la ficción, y ahora ha escrito su mejor obra hasta el momento, la más provocadora:. Publicado también como texto impreso. "Penguin Random House Grupo Editorial España". Ficción moderna y contemporánea. Rodríguez Juiz, Cruz. traductor..', NULL, 28760, NULL, 18.0, 'Almacén', '2025-12-18', TRUE, NULL, 1, 'Frey, James', FALSE, FALSE, FALSE, NULL)
