VALUES ('02292884', '84-00-07577-3', 'La tapicería en Madrid (1570-1640)', 1996, 469, '24 cm. Cruz Yábar, María Teresa 1970-. Bibliografía. Tapices renacentistas. Madrid..Es un estudio profundo sobre la tapicería madrileña en la Edad Moderna, un territorio donde la artesanía se vuelve relato, y donde cada hilo es memoria política, económica y simbólica. Un libro que, conociéndote, podría convertirse en un mapa ritual para pensar la materialidad como narrativa.', NULL, 28760, NULL, 39.0, 'Almacén', '2025-12-20', TRUE, NULL, 1, 'Cruz Yábar, María Teresa', FALSE, FALSE, FALSE, NULL)
